#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,k,m,a[1005];
    cin>>n>>k>>m;
    for(int i=0;i<n;i++) a[i]=i+1;
    for(int i=1;i<=k;i++){
        int t[1005];
        for(int j=0;j<n/2;j++){
            t[j*2]=a[j];
        }
        for(int j=n/2;j<n;j++){
            t[(j-n/2)*2+1]=a[j];
        }
        for(int i=0;i<n;i++) a[i]=t[i];
    }
    cout<<a[m-1];
    return 0;
}
